const LOGO_VB = '0 0 504.0 141.0';
const LOGO_AR = 3.5745;

export function AGlyph({ size = 28, fill = '#fff' }: { size?: number; fill?: string }) {
  return (
    <svg width={size} height={size} viewBox={A_VB} fill="none" aria-hidden>
      <path d={A_D} fill={fill} fillRule="evenodd" />
    </svg>
  );
}

export function Wordmark({ size = 14, color = '#FAFAFA' }: { size?: number; color?: string }) {
  return (
    <svg
      height={size}
      width={size * LOGO_AR}
      viewBox={LOGO_VB}
      fill="none"
      style={{ display: 'block' }}
      aria-label="Accesly"
    >
      <path d={LOGO_D} fill={color} fillRule="evenodd" />
    </svg>
  );
}

/**
 * Tile icon: A blanca sobre fondo lavanda. La variante "app icon" oficial
 * — útil para landing screen y badges.
 *
 * El bg usa `var(--accesly-primary, var(--lav))` — el SDK escribe el color
 * elegido en el dashboard a `--accesly-primary` al boot, así que si el dev
 * lo seteó el Mark lo respeta automáticamente. Sin branding, fallback al
 * lavender de Accesly.
 */
export function Mark({ size = 56, radius = 18 }: { size?: number; radius?: number }) {
  return (
    <div
      style={{
        width: size,
        height: size,
        borderRadius: radius,
        background: 'var(--accesly-primary, var(--lav))',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        boxShadow: '0 12px 32px rgba(139,108,231,.4)',
        flexShrink: 0,
      }}
    >
      <AGlyph size={size * 0.56} fill="#fff" />
    </div>
  );
}

/**
 * Underline acento — la firma del brand. Usa el gradient brand-aware
 * (`--accesly-grad`) que el SDK compone al boot a partir del primaryColor
 * del dashboard. Fallback al gradient lavender-mint default.
 */
export function Accent({ w = 40 }: { w?: number }) {
  return (
    <div
      style={{
        width: w,
        height: 3,
        borderRadius: 3,
        background: 'var(--accesly-grad, var(--grad))',
        marginTop: 7,
      }}
      aria-hidden
    />
  );
}
